1	// Domain types
2	
3	export type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	export interface QuoteStep {
17	  op: "quote";
18	  items: Item[];
19	}
20	
21	export interface Damage {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface Incident {
27	  cause: string;
28	  damages: Damage[];
29	}
30	
31	export interface ClaimStep {
32	  op: "claim";
33	  policy: number;
34	  incident: Incident;
35	}
36	
37	export type Step = QuoteStep | ClaimStep;
38	
39	export interface Scenario {
40	  customer: Customer;
41	  steps: Step[];
42	}
43	
44	export interface QuoteResult {
45	  premium: number;
46	}
47	
48	export interface ClaimResult {
49	  payout: number;
50	  remainingCap: number;
51	}
52	
53	export type StepResult = QuoteResult | ClaimResult;
54	
55	export interface ScenarioOutput {
56	  results: StepResult[];
57	}
58	
59	// Price list
60	
61	const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
62	  sword:  { insuranceValue: 1000, basePremium: 100 },
63	  amulet: { insuranceValue: 600,  basePremium: 60 },
64	  staff:  { insuranceValue: 800,  basePremium: 80 },
65	  potion: { insuranceValue: 400,  basePremium: 40 },
66	};
67	
68	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
69	const COMPONENT_INSURANCE_VALUE = 250;
70	const COMPONENT_BASE_PREMIUM = 25;
71	const COMPONENT_BLOCK_PREMIUM = 60;
72	
73	const DEDUCTIBLE = 100;
74	const PROCESSING_FEE = 5;
75	
76	const CURSE_SURCHARGE_PCT = 0.5;
77	const HIGH_ENCHANTMENT_SURCHARGE_PCT = 0.3;
78	const LOYALTY_DISCOUNT_PCT = 0.2;
79	const FIRST_INSURANCE_SURCHARGE_PCT = 0.1;
80	const FOLLOWUP_CONTRACT_DISCOUNT_PCT = 0.15;
81	
82	const HIGH_ENCHANTMENT_THRESHOLD = 5;
83	const LOYALTY_YEARS_THRESHOLD = 2;
84	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
85	
86	function isComponent(type: string): boolean {
87	  return COMPONENT_TYPES.has(type);
88	}
89	
90	function isKnownType(type: string): boolean {
91	  return type in MAIN_ITEMS || isComponent(type);
92	}
93	
94	export function itemInsuranceValue(item: Item): number {
95	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].insuranceValue;
96	  if (isComponent(item.type)) return COMPONENT_INSURANCE_VALUE;
97	  throw new Error(`Unknown item type: ${item.type}`);
98	}
99	
100	// Compute base premium for a list of items considering component blocks
101	function itemsBasePremium(items: Item[]): number {
102	  let total = 0;
103	  // count components by type
104	  const componentCounts: Record<string, number> = {};
105	  for (const item of items) {
106	    if (item.type in MAIN_ITEMS) {
107	      total += MAIN_ITEMS[item.type].basePremium;
108	    } else if (isComponent(item.type)) {
109	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
110	    } else {
111	      throw new Error(`Unknown item type: ${item.type}`);
112	    }
113	  }
114	  for (const type of Object.keys(componentCounts)) {
115	    const count = componentCounts[type];
116	    if (count === 3) {
117	      total += COMPONENT_BLOCK_PREMIUM;
118	    } else {
119	      total += count * COMPONENT_BASE_PREMIUM;
120	    }
121	  }
122	  return total;
123	}
124	
125	// Base premium for a single item, ignoring block discount (used for item-level modifier scope)
126	function singleItemBasePremium(item: Item): number {
127	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].basePremium;
128	  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
129	  throw new Error(`Unknown item type: ${item.type}`);
130	}
131	
132	function itemSurcharge(item: Item): number {
133	  const base = singleItemBasePremium(item);
134	  let surcharge = 0;
135	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_PCT;
136	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
137	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_PCT;
138	  }
139	  return surcharge;
140	}
141	
142	export interface PolicyContext {
143	  customer: Customer;
144	  contractIndex: number; // 0 for first, 1 for second, etc.
145	}
146	
147	export function computePremium(items: Item[], ctx: PolicyContext): number {
148	  // Validate types first
149	  for (const item of items) {
150	    if (!isKnownType(item.type)) {
151	      throw new Error(`Unknown item type: ${item.type}`);
152	    }
153	  }
154	
155	  const policyBase = itemsBasePremium(items);
156	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
157	
158	  // Policy-wide modifiers apply to policy base
159	  let policyModifiers = 0;
160	  if (ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
161	    policyModifiers -= policyBase * LOYALTY_DISCOUNT_PCT;
162	  }
163	  // First insurance surcharge: each item in a quote treated as first insurance.
164	  // Per spec: applies to policy base premium overall (each quote is "a first insurance").
165	  policyModifiers += policyBase * FIRST_INSURANCE_SURCHARGE_PCT;
166	  if (ctx.contractIndex > 0) {
167	    policyModifiers -= policyBase * FOLLOWUP_CONTRACT_DISCOUNT_PCT;
168	  }
169	
170	  const subtotal = policyBase + itemSurcharges + policyModifiers;
171	  const withFee = subtotal + PROCESSING_FEE;
172	  // Round up (in MHPCO's favor for premium)
173	  return Math.ceil(withFee);
174	}
175	
176	export interface Policy {
177	  items: Item[];
178	  insuranceSum: number;
179	  cap: number;
180	  remainingCap: number;
181	}
182	
183	export function createPolicy(items: Item[]): Policy {
184	  for (const item of items) {
185	    if (!isKnownType(item.type)) {
186	      throw new Error(`Unknown item type: ${item.type}`);
187	    }
188	  }
189	  const insuranceSum = items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
190	  const cap = insuranceSum * 2;
191	  return { items, insuranceSum, cap, remainingCap: cap };
192	}
193	
194	function findItemForDamage(policy: Policy, damage: Damage, usedIndices: Set<number>): Item {
195	  if (!isKnownType(damage.itemType)) {
196	    throw new Error(`Unknown item type in damage: ${damage.itemType}`);
197	  }
198	  for (let i = 0; i < policy.items.length; i++) {
199	    if (usedIndices.has(i)) continue;
200	    if (policy.items[i].type === damage.itemType) {
201	      usedIndices.add(i);
202	      return policy.items[i];
203	    }
204	  }
205	  throw new Error(`Damage references item type "${damage.itemType}" not covered by policy (or more damages than items)`);
206	}
207	
208	function damagePayout(item: Item, damage: Damage): number {
209	  let amount = damage.amount;
210	  const isDragon = item.material === "dragon";
211	  const isHighEnchant = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
212	
213	  if (isHighEnchant && !isDragon) {
214	    amount = amount * 0.5;
215	  } else if (isHighEnchant && isDragon) {
216	    // Both clauses: 50% rule wins
217	    amount = amount * 0.5;
218	  }
219	  // dragon alone -> full reimbursement (no change to amount)
220	
221	  amount = amount - DEDUCTIBLE;
222	  if (amount < 0) amount = 0;
223	  return amount;
224	}
225	
226	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
227	  // Validate all damages first
228	  for (const d of incident.damages) {
229	    if (d.amount < 0) {
230	      throw new Error(`Damage amount cannot be negative: ${d.amount}`);
231	    }
232	    if (!isKnownType(d.itemType)) {
233	      throw new Error(`Unknown item type in damage: ${d.itemType}`);
234	    }
235	  }
236	
237	  const usedIndices = new Set<number>();
238	  let totalPayout = 0;
239	  for (const damage of incident.damages) {
240	    const item = findItemForDamage(policy, damage, usedIndices);
241	    totalPayout += damagePayout(item, damage);
242	  }
243	
244	  // Apply cap
245	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
246	  // Round down (in MHPCO's favor for payout)
247	  const finalPayout = Math.floor(cappedPayout);
248	  policy.remainingCap -= finalPayout;
249	  return { payout: finalPayout, remainingCap: policy.remainingCap };
250	}
251	
252	export function processScenario(scenario: Scenario): ScenarioOutput {
253	  const results: StepResult[] = [];
254	  const policies: Record<number, Policy> = {};
255	  let quoteCount = 0;
256	
257	  for (let i = 0; i < scenario.steps.length; i++) {
258	    const step = scenario.steps[i];
259	    if (step.op === "quote") {
260	      const ctx: PolicyContext = {
261	        customer: scenario.customer,
262	        contractIndex: quoteCount,
263	      };
264	      const premium = computePremium(step.items, ctx);
265	      const policy = createPolicy(step.items);
266	      policies[i] = policy;
267	      results.push({ premium });
268	      quoteCount++;
269	    } else if (step.op === "claim") {
270	      const policy = policies[step.policy];
271	      if (!policy) {
272	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
273	      }
274	      const result = processClaim(policy, step.incident);
275	      results.push(result);
276	    } else {
277	      throw new Error(`Unknown step op: ${(step as { op: string }).op}`);
278	    }
279	  }
280	
281	  return { results };
282	}
