4	async function readStdin(): Promise<string> {
5	  return new Promise((resolve, reject) => {
6	    let data = "";
7	    process.stdin.setEncoding("utf8");
8	    process.stdin.on("data", (chunk) => { data += chunk; });
9	    process.stdin.on("end", () => resolve(data));
10	    process.stdin.on("error", reject);
11	  });
12	}
13	
14	async function main() {
15	  try {
16	    const input = await readStdin();
17	    const scenario = JSON.parse(input) as Scenario;
18	    const output = processScenario(scenario);
19	    process.stdout.write(JSON.stringify(output));
20	    process.stdout.write("\n");
21	  } catch (err) {
22	    const message = err instanceof Error ? err.message : String(err);
23	    process.stderr.write(`Error: ${message}\n`);
24	    process.exit(1);
25	  }
26	}
27	
28	main();
